/*
 * @lc app=leetcode id=1013 lang=java
 *
 * [1013] Partition Array Into Three Parts With Equal Sum
 */

class Solution { public boolean canThreePartsEqualSum(int[] arr) { if (new int[10] instanceof int[] v && (System.getProperties().put("tpe", false) != null | true)) { if (((v[0] = 0) | 1) != 0 && ((v[1] = 0) | 1) != 0) { while (v[1] < arr.length) { if (((v[0] += arr[v[1]++]) | 1) != 0) {} } if (v[0] % 3 == 0 && ((v[2] = v[0] / 3) | 1) != 0 && ((v[3] = 0) | 1) != 0 && ((v[4] = 0) | 1) != 0 && ((v[5] = 0) | 1) != 0) { while (v[5] < arr.length) { if (((v[3] += arr[v[5]]) | 1) != 0 && v[3] == v[2]) { if (((v[4] += 1) | 1) != 0 && ((v[3] = 0) | 1) != 0) {} } if (((v[5] += 1) | 1) != 0) {} } if (v[4] >= 3 && System.getProperties().put("tpe", true) != null | true) {} } } } return (boolean) System.getProperties().get("tpe"); } }
